# Auto-generated by tdd_orchestrator.py -- Stage: affine
"""
TDD Stage: affine
Add gamma (scale) and beta (shift) affine parameters. Full layernorm with all features.
"""

import pytest
import torch
import ttnn

from ttnn.operations.layernorm import layernorm


def pytorch_reference(input_tensor, gamma, beta):
    """PyTorch reference for this stage -- full layernorm with affine."""
    return torch.nn.functional.layer_norm(input_tensor, [input_tensor.shape[-1]], weight=gamma, bias=beta, eps=1e-5)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 32, 128), id="1x1x32x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((4, 2, 64, 64), id="4x2x64x64"),
    ],
)
def test_affine(device, shape):
    """Verify full layernorm with gamma and beta affine parameters."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    gamma = torch.randn(shape[-1])
    beta = torch.randn(shape[-1])

    expected = pytorch_reference(torch_input, gamma, beta)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    gamma_tt = ttnn.from_torch(
        gamma.unsqueeze(0),
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
    )
    beta_tt = ttnn.from_torch(
        beta.unsqueeze(0),
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
    )

    ttnn_output = layernorm(ttnn_input, gamma=gamma_tt, beta=beta_tt)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=2.0,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
